class Solution {
public:
    int compress(vector<char>& chars) {
        int count[25] = {0}; // count array to store character counts
        int result = 0; // stores the compressed string length

        for (int i = 0; i < chars.size(); i++) {
            count[chars[i]]++;
            if (count[chars[i]] > 1) {
                result += count[chars[i]] - 1;
                count[chars[i]] = 1;
            }
        }

        return result;
    }
};
```

